func lower(f byexample.Feature) (out, label string, err error) {
	res, terr := backend.Transpile(f.Source)
	switch f.OutputKind {
	case "error":
		if terr == nil {
			return "", "", fmt.Errorf("expected rejection, but transpile succeeded")
		}
		return strings.TrimRight(terr.Error(), "\n"), "rejected with", nil
	case "test":
		if terr != nil {
			return "", "", fmt.Errorf("live transpile failed: %w", terr)
		}
		return res.Test, "generated _test.go", nil
	default:
		if terr != nil {
			return "", "", fmt.Errorf("live transpile failed: %w", terr)
		}
		return res.Go, "transpiles to", nil
	}
}

